#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e9;
int s[20],b[20];
int n;
int mini=MAXN;
void choose(int x,int S,int B){
	if(x>n){
		if(S==1&&B==0)return;
		mini=min(mini,abs(S-B));
	//	cout<<S<<" "<<B<<" "<<mini<<endl;
		return;
	}
	choose(x+1,S*s[x],B+b[x]);
	choose(x+1,S,B);
}
int main()
{

	cin>>n;
	for(int i=1;i<=n;i++)cin>>s[i]>>b[i];
	choose(1,1,0);
	cout<<mini;
}
